import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as a}from"./chunks/installing-mods.gZ3xnRXE.js";const o=JSON.parse(`{"title":"安装模组","description":"Fabric 模组安装的逐步指南","frontmatter":{"title":"安装模组","description":"Fabric 模组安装的逐步指南","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"zh_cn/1.21.10/players/installing-mods.md","filePath":"versions/1.21.10/translated/zh_cn/players/installing-mods.md","lastUpdated":1766682904000}`);var s={name:`zh_cn/1.21.10/players/installing-mods.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">安装模组 <a class="header-anchor" href="#h1" aria-label="Permalink to “安装模组”">​</a></h1><p>这个指南将引导你使用 Minecraft 启动器安装 Fabric 模组。</p><p>对于第三方启动器，应该参见这些第三方启动器的文档。</p><h2 id="1-download-the-mod" tabindex="-1">1. 下载模组 <a class="header-anchor" href="#1-download-the-mod" aria-label="Permalink to “1. 下载模组”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>你应该只从你信任的来源下载模组。 关于寻找模组的更多信息，请看<a href="./finding-mods">寻找可信的模组</a>指南。</p></div><p>大多数模组都需要 Fabric API，可从 <a href="https://modrinth.com/mod/fabric-api" target="_blank" rel="noreferrer">Modrinth</a> 或 <a href="https://curseforge.com/minecraft/mc-mods/fabric-api" target="_blank" rel="noreferrer">CurseForge</a> 下载。</p><p>下载模组时，请确保：</p><ul><li>能在你想玩的 Minecraft 版本上运行。 例如，在 1.20 运行的模组在 1.20.2 可能无法运行。</li><li>模组是用于 Fabric 的，而不是其他模组加载器。</li><li>此外，适用于正确的 Minecraft（Java 版）的版本。</li></ul><h2 id="2-move-the-mod-to-the-mods-folder" tabindex="-1">2. 将模组移到 <code>mods</code> 文件夹 <a class="header-anchor" href="#2-move-the-mod-to-the-mods-folder" aria-label="Permalink to “2. 将模组移到 mods 文件夹”">​</a></h2><p>各个操作系统中，模组文件夹的位置如下所示：</p><p>你通常可以将这些路径粘贴到文件资源管理器的地址栏中，以快速导航到文件夹。</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-49" id="tab-50" checked><label data-title="Windows" for="tab-50">Windows</label><input type="radio" name="group-49" id="tab-51"><label data-title="macOS" for="tab-51">macOS</label><input type="radio" name="group-49" id="tab-52"><label data-title="Linux" for="tab-52">Linux</label></div><div class="blocks"><div class="language- active"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft\\mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft/mods</span></span></code></pre></div><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft/mods</span></span></code></pre></div></div></div><p>找到 <code>mods</code> 文件夹后，就可以将模组 <code>.jar</code> 文件移入其中。</p><p><img src="/assets/players/installing-mods.png" alt="已在模组文件夹中安装模组" loading="lazy"></p><h2 id="3-you-re-done" tabindex="-1">3. 搞定！ <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. 搞定！”">​</a></h2><p>将模组移入 <code>mods</code> 文件夹后，你可以打开 Minecraft 启动器，从左下角的下拉菜单中选择 Fabric 配置文件，然后按下 <code>Play</code>！</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="选择了 Fabric 配置的官方启动器" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">疑难解答 <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to “疑难解答”">​</a></h2><p>如果在遵循本指南时遇到任何问题，可以在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 频道中寻求帮助。</p><p>也可以尝试阅读疑难解答页面，尝试自己解决问题：</p><ul><li><a href="./troubleshooting/crash-reports">崩溃报告</a></li><li><a href="./troubleshooting/uploading-logs">上传日志</a></li></ul>`,21)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};